mapper.sql:
SELECT A.BILL_YM , A.WORK_DT , A.SVC_CNTR_NUM , A.BILL_ITEM_CD , A.BILL_ITEM_NM , A.UNPAY_AMNT , B.CONTRACT_NUM , B.SUB_LINK_NAME AS CUST_NM , B.SUBSCRIBER_NO AS SVC_TEL_NUM , B.SUB_STATUS , FN_GET_CODENM('MSP0003', B.SUB_STATUS) AS SUB_STATUS_NM , B.LST_COM_ACTV_DATE AS OPEN_DT , DECODE(B.SUB_STATUS, 'C', SUBSTR(B.SUB_STATUS_DATE, 1, 8), '') AS TMNT_DT , ( CASE WHEN B.CONTRACT_NUM != B.SVC_CNTR_NO THEN 'Y' ELSE 'N' END ) AS MCN_YN , FN_GET_ORGNM(B.OPEN_AGNT_CD) AS OPEN_AGNT_NM FROM CLS_UNPD_DATA A , MSP_JUO_SUB_INFO B WHERE 1 = 1 AND (A.SVC_CNTR_NUM = B.SVC_CNTR_NO OR A.SVC_CNTR_NUM = B.CONTRACT_NUM) AND A.BILL_YM = #{billYm}
AND B.OPEN_AGNT_CD = #{cntpntShopId}
AND (B.CONTRACT_NUM = #{searchVal} OR B.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchVal}))
AND B.SUB_LINK_NAME LIKE '%' || #{searchVal} || '%'
AND B.SUBSCRIBER_NO = #{searchVal}
AND A.BILL_ITEM_CD = #{billItemCd}
AND B.SUB_STATUS = #{subStatus}
AND ( CASE WHEN B.CONTRACT_NUM != B.SVC_CNTR_NO THEN 'Y' ELSE 'N' END ) = #{mcnYn}
